example.code:
import Image from 'next/image';
import dynamic from 'next/dynamic';

// LCP image: priority eager load
<Image
  src={product.image}
  alt={product.name}
  width={400}
  height={400}
  priority={true}
  placeholder="blur"
  blurDataURL={product.blurDataUrl}
/>

// Non-critical below-fold widget
const CommentsSection = dynamic(() => import('./Comments'), {
  loading: () => <Skeleton />,
  ssr: false
});
